 1	import * as React from 'react';
 2	import { parseNamespaceName } from '@odf/mco/utils';
 3	import { getName } from '@odf/shared/selectors';
 4	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 5	import {
 6	  Text,
 7	  Badge,
 8	  TextContent,
 9	  TextVariants,
10	  Flex,
11	  FlexItem,
12	} from '@patternfly/react-core';
13	import { ManagedClusterInfoType } from './utils/reducer';
14	import './create-dr-policy.scss';
15	
16	type SelectedClusterViewProps = {
17	  index: number;
18	  cluster: ManagedClusterInfoType;
19	};
20	
21	export const SelectedClusterView: React.FC<SelectedClusterViewProps> = ({
22	  index,
23	  cluster,
24	}) => {
25	  const { t } = useCustomTranslation();
26	  const { odfInfo } = cluster;
27	  const [storageClusterName] = parseNamespaceName(
28	    odfInfo.storageClusterInfo.storageClusterNamespacedName
29	  );
30	  return (
31	    <Flex
32	      display={{ default: 'inlineFlex' }}
33	      className="mco-create-data-policy__flex"
34	    >
35	      <FlexItem>
36	        <Badge key={index} isRead>
37	          {index}
38	        </Badge>
39	      </FlexItem>
40	      <FlexItem>
41	        <TextContent>
42	          <Text component={TextVariants.p}>{getName(cluster)}</Text>
43	          {!!storageClusterName ? (
44	            <Text component={TextVariants.small}>{storageClusterName}</Text>
45	          ) : (
46	            <Text component={TextVariants.small}>
47	              {t('Information unavailable')}
48	            </Text>
49	          )}
50	        </TextContent>
51	      </FlexItem>
52	    </Flex>
53	  );
54	};

